import { redirect } from 'next/navigation';
import { createServerSupabase } from '@/lib/supabaseServer';
import { AppShell } from '@/components/AppShell';
import { MetricCard } from '@/components/MetricCard';
import { ProgressCard } from '@/components/ProgressCard';
import { goalLabel, percentFromDays, stageFromDays } from '@/lib/utils';
export default async function Dashboard(){const supabase=createServerSupabase();const {data:{user}}=await supabase.auth.getUser();if(!user)redirect('/auth/login');const {data:profile}=await supabase.from('profiles').select('*').eq('user_id',user.id).single();if(!profile||!profile.onboarding_completed)redirect('/onboarding');const {count:days}=await supabase.from('daily_progress').select('*',{count:'exact',head:true}).eq('user_id',user.id).eq('completed',true);const percent=percentFromDays(days??0);const stage=stageFromDays(days??0);return <AppShell><div className="mb-6"><span className="badge">Etapa {stage} de 10</span><h1 className="mt-3 text-4xl font-black">Olá, {profile.full_name}</h1><p className="text-slate-600">Sua evolução é construída um dia por vez.</p></div><div className="grid gap-4 md:grid-cols-4"><MetricCard label="Peso inicial" value={`${profile.initial_weight_kg} kg`}/><MetricCard label="Peso atual" value={`${profile.current_weight_kg} kg`}/><MetricCard label="Altura" value={`${profile.height_cm} cm`}/><MetricCard label="Dias concluídos" value={days??0} sub="Meta: 28 dias"/></div><div className="mt-6 grid gap-4 md:grid-cols-2"><ProgressCard title="Progresso da transformação" percent={percent}/><div className="card"><h2 className="text-xl font-black">Seu foco</h2><p className="mt-2 text-slate-600">Objetivo: {goalLabel[profile.goal]} • Nível: {profile.level} • {profile.training_frequency} treinos/semana</p><p className="mt-4 rounded-2xl bg-brand-50 p-4 font-semibold text-brand-700">Hoje é uma chance de provar para você mesmo que a mudança já começou.</p></div></div><div className="mt-6 grid gap-4 md:grid-cols-2"><div className="card"><h2 className="text-xl font-black">Resumo da semana</h2><p className="mt-2 text-slate-600">Treino recomendado: 3 a 5 sessões, alternando força, mobilidade e caminhada.</p></div><div className="card"><h2 className="text-xl font-black">Plano alimentar</h2><p className="mt-2 text-slate-600">Base simples: proteínas magras, legumes, frutas, água e consistência.</p></div></div></AppShell>}
